// Generated by AI (UnitTest MCP)
import { execFileSync, spawnSync } from "node:child_process";
import { existsSync, mkdirSync, mkdtempSync, rmSync, writeFileSync } from "node:fs";
import { tmpdir } from "node:os";
import { dirname, join } from "node:path";
import { fileURLToPath } from "node:url";

import { afterEach, describe, expect, it } from "vitest";

const runner = join(
  dirname(fileURLToPath(import.meta.url)),
  "../../../scripts/cargo-precommit.mjs"
);
const temporaryDirectories = [];

afterEach(() => {
  for (const directory of temporaryDirectories.splice(0)) {
    rmSync(directory, { recursive: true, force: true });
  }
});

const git = (cwd, args) =>
  execFileSync("git", args, { cwd, encoding: "utf8", stdio: "pipe" }).trim();

describe("cargo-precommit snapshot validation", () => {
  it("tests committed bytes and metadata without registering another worktree", () => {
    const root = mkdtempSync(join(tmpdir(), "mindleak-cargo-hook-"));
    temporaryDirectories.push(root);
    const repo = join(root, "repo");
    const remote = join(root, "remote.git");
    const crate = join(repo, "crates", "demo");
    const source = join(crate, "src");
    mkdirSync(source, { recursive: true });
    writeFileSync(join(repo, "Cargo.toml"), '[workspace]\nmembers = ["crates/demo"]\n');
    writeFileSync(
      join(crate, "Cargo.toml"),
      '[package]\nname = "demo"\nversion = "0.1.0"\nedition = "2021"\n'
    );
    writeFileSync(
      join(source, "lib.rs"),
      "pub fn answer() -> u8 { 42 }\n\n#[test]\nfn answers() { assert_eq!(answer(), 42); }\n"
    );
    git(repo, ["init", "-b", "main"]);
    git(repo, ["config", "user.name", "Cargo Hook Test"]);
    git(repo, ["config", "user.email", "cargo-hook@example.invalid"]);
    git(repo, ["add", "."]);
    git(repo, ["commit", "-m", "valid workspace"]);
    git(root, ["init", "--bare", remote]);
    git(repo, ["remote", "add", "origin", remote]);
    git(repo, ["push", "-u", "origin", "main"]);

    writeFileSync(join(source, "lib.rs"), "pub fn answer() -> u8 { 43 }\n");
    git(repo, ["add", "crates/demo/src/lib.rs"]);
    git(repo, ["commit", "-m", "change demo"]);

    writeFileSync(join(source, "lib.rs"), "this is not valid Rust {{{\n");
    writeFileSync(join(crate, "Cargo.toml"), "this is not valid TOML {{{\n");
    const result = spawnSync(process.execPath, [runner, "test", "push"], {
      cwd: repo,
      encoding: "utf8",
      timeout: 60_000,
    });

    expect(result.status, `${result.stdout}\n${result.stderr}`).toBe(0);
    expect(existsSync(join(repo, "target", "hooks"))).toBe(true);
    expect(existsSync(join(repo, ".git", "worktrees"))).toBe(false);
  }, 60_000);
});
